import{_ as e,o as t,c as i,ae as l}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"Branch Plan: Merchant Registry (On-chain Catalogs)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/branch_merchant_registry.md","filePath":"docs/plans/branch_merchant_registry.md"}'),o={name:"docs/plans/branch_merchant_registry.md"};function r(c,a,n,d,s,h){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="branch-plan-merchant-registry-on-chain-catalogs" tabindex="-1">Branch Plan: Merchant Registry (On-chain Catalogs) <a class="header-anchor" href="#branch-plan-merchant-registry-on-chain-catalogs" aria-label="Permalink to &quot;Branch Plan: Merchant Registry (On-chain Catalogs)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Enable on-chain merchant discovery via a lightweight registry and catalog accounts, so agents and the hub can list all merchants and filter catalogs by category using Helius RPC.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>New program <code>xb77_registry</code> (preferred) or minimal module inside <code>xb77_gateway</code>.</li><li>Merchant account + Catalog account model (one merchant, many catalogs).</li><li>Instructions to create/update merchants and catalogs.</li><li>SDK helper stubs or interfaces for registry reads (no RPC wiring in this branch).</li><li>UI plan for the hub to list merchants and show catalogs.</li></ul><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Payment execution logic.</li><li>Checkout and receipt flows.</li><li>Full merchant onboarding UX.</li><li>Helius RPC integration (handled in Infra/Observability branch).</li></ul><h2 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h2><p><strong>Merchant Account</strong></p><ul><li><code>merchant_id</code> (string or bytes)</li><li><code>owner_pubkey</code> (Pubkey)</li><li><code>catalog_count</code> (u32)</li><li><code>created_at</code> (u64)</li><li><code>updated_at</code> (u64)</li></ul><p><strong>Catalog Account</strong></p><ul><li><code>merchant_id</code> (string or bytes)</li><li><code>catalog_id</code> (u64)</li><li><code>category</code> (u8)</li><li><code>catalog_url</code> (string)</li><li><code>metadata_hash</code> (bytes32, optional)</li><li><code>updated_at</code> (u64)</li></ul><h2 id="pda-seeds" tabindex="-1">PDA Seeds <a class="header-anchor" href="#pda-seeds" aria-label="Permalink to &quot;PDA Seeds&quot;">​</a></h2><ul><li>Merchant: <code>[&quot;merchant&quot;, merchant_id]</code></li><li>Catalog: <code>[&quot;catalog&quot;, merchant_id, catalog_id]</code></li></ul><h2 id="instructions" tabindex="-1">Instructions <a class="header-anchor" href="#instructions" aria-label="Permalink to &quot;Instructions&quot;">​</a></h2><ol><li><code>init_merchant(merchant_id)</code></li><li><code>add_catalog(merchant_id, catalog_id, category, catalog_url, metadata_hash?)</code></li><li><code>update_catalog(merchant_id, catalog_id, category?, catalog_url?, metadata_hash?)</code></li><li><code>deactivate_catalog(merchant_id, catalog_id)</code> (optional)</li></ol><h2 id="hub-integration-deferred" tabindex="-1">Hub Integration (Deferred) <a class="header-anchor" href="#hub-integration-deferred" aria-label="Permalink to &quot;Hub Integration (Deferred)&quot;">​</a></h2><ul><li>Hub should consume registry data via SDK helper interfaces.</li><li>Helius RPC wiring and caching live in Infra/Observability branch.</li></ul><h2 id="sdk-integration" tabindex="-1">SDK Integration <a class="header-anchor" href="#sdk-integration" aria-label="Permalink to &quot;SDK Integration&quot;">​</a></h2><ul><li>Add <code>registry</code> helpers: <code>listMerchants</code>, <code>listCatalogs</code>, <code>listCatalogsByCategory</code>.</li><li>Return stable types for UI consumption.</li></ul><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li>On-chain registry program + deploy script (devnet).</li><li>Hub registry fetch + UI list.</li><li>SDK helpers + docs.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Program ID allocation.</li><li>Helius RPC endpoint.</li><li>Decision: <code>xb77_registry</code> vs <code>xb77_gateway</code> extension.</li></ul><h2 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h2><ul><li>Account size limits for string fields.</li><li>Helius query latency for large registries.</li></ul><h2 id="fallback" tabindex="-1">Fallback <a class="header-anchor" href="#fallback" aria-label="Permalink to &quot;Fallback&quot;">​</a></h2><ul><li>Store catalog_url off-chain and keep only hash on-chain.</li></ul><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><ul><li>BP1: Merchant account created on devnet.</li><li>BP2: Catalog account created and fetched via Helius.</li><li>BP3: Hub UI lists merchants + catalogs with category filter.</li></ul>',30)])])}const b=e(o,[["render",r]]);export{g as __pageData,b as default};
